SELECT incident_type, COUNT(*) AS incident_count
FROM security_incidents
GROUP BY incident_type;

SELECT COUNT(*) AS successful_access_attempts
FROM plan_access_logs
WHERE status = 'success';

SELECT user_id, STRFTIME('%Y-%m-%d', access_date) AS formatted_access_date
FROM plan_access_logs
WHERE access_date > '2023-04-01';

SELECT region_count
FROM multi_region_linkage
WHERE plan_id = 3;

SELECT metric_type
FROM performance_metrics
WHERE value = (SELECT MAX(value) FROM performance_metrics);

SELECT MAX(access_date) 
FROM plan_access_logs 
WHERE plan_id = 2;
